'use client';
import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Menu } from 'lucide-react';
import { useWorkflow, useCascade } from '@cascaide-ts/react';
import { v4 as uuidv4 } from 'uuid';
import { Sidebar } from './sidebar';
import { InputBar } from './input.tsx';
import { MessageList } from './message-list';


// --- Types ---

interface ChatProps {
  nodeId: string;
}

type ToolCall = {
  function: {
    name: string;
    arguments: string;
  };
};

type Message = {
  role: 'user' | 'assistant' | 'tool';
  content: string | null;
  tool_calls?: ToolCall[];
  tool_call_id?: string;
  name?: string;
};



// --- Main Component ---

export default function Chat({ nodeId }: ChatProps) {
  const [input, setInput] = useState('');
  const userId = 'guest-id';
  const userName = 'there';
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isSidebarExpanded, setIsSidebarExpanded] = useState(true);
  const { addActiveNode } = useWorkflow(nodeId);

  // Single ID serves as both chatId and cascadeId
  const [chatId, setChatId] = useState<string>(uuidv4());

  const { cascadeState, isComplete } = useCascade(chatId);
  const [conversationMessages, setConversationMessages] = useState<Message[]>([]);

  const isProcessing = useMemo(() =>
    !isComplete && !!cascadeState,
    [isComplete, cascadeState]
  );

  const currentChatHasUserMessages = useMemo(() =>
    conversationMessages.some(m => m.role === 'user'),
    [conversationMessages]
  );

  useEffect(() => {
    if (!cascadeState?.history) return;

    const cascadeHistory = cascadeState.history;

    if (cascadeHistory.length !== conversationMessages.length) {
      setConversationMessages(cascadeHistory);
      return;
    }

    const lastCascadeMsg = cascadeHistory[cascadeHistory.length - 1];
    const lastConvMsg = conversationMessages[conversationMessages.length - 1];

    if (!lastCascadeMsg || !lastConvMsg) return;

    const contentChanged = lastCascadeMsg.content !== lastConvMsg.content;
    const toolCallsChanged = JSON.stringify(lastCascadeMsg.tool_calls) !== JSON.stringify(lastConvMsg.tool_calls);

    if (contentChanged || toolCallsChanged) {
      setConversationMessages(cascadeHistory);
    }
  }, [cascadeState?.history, cascadeState?.status]);

  const toggleSidebarExpansion = useCallback(() => {
    setIsSidebarExpanded(prev => !prev);
  }, []);

  const startNewChat = useCallback(() => {
    const newId = uuidv4();
    setChatId(newId);
    setConversationMessages([]);
    setInput('');
  }, []);

  const selectChat = useCallback((id: string) => {
    if (id === chatId) return;
    // TODO: load selected chat history
  }, [chatId]);

  const handleSendMessage = useCallback(async (message: string) => {
    if (!message.trim() || isProcessing || !userId) return;

    const newUserMessage: Message = { role: 'user', content: message.trim() };
    setConversationMessages(prev => [...prev, newUserMessage]);
    setInput('');

    await addActiveNode('supervisorAgentNode', {
      cascadeId: chatId,
      history: [newUserMessage],
      userId,
    });
  }, [isProcessing, userId, addActiveNode, chatId]);

  const handleToolResponse = useCallback(async (toolResponse: Message) => {
    setConversationMessages(prev => [...prev, toolResponse]);
    setInput('');

    await addActiveNode('supervisorAgentNode', {
      cascadeId: chatId,
      history: [toolResponse],
      userId,
    });
  }, [addActiveNode, chatId]);

  const handleKeyPress = useCallback((e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage(input);
    }
  }, [input, handleSendMessage]);

  const isEmptyChat = !currentChatHasUserMessages;

  return (
    <div className="w-screen h-screen flex bg-blur from-blue-50 via-white to-purple-50">

      {/* Sidebar */}
      <Sidebar
        history={[]}
        currentChatId={chatId}
        onNewChat={startNewChat}
        onSelectChat={selectChat}
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
        isExpanded={isSidebarExpanded}
        toggleExpansion={toggleSidebarExpansion}
      />

      {/* Main Content */}
      <div className="flex-1 flex flex-col min-w-0 transition-all duration-300 ease-in-out">
        {!isSidebarOpen && (
          <button
            onClick={() => setIsSidebarOpen(true)}
            className="lg:hidden absolute top-5 left-6 z-50 p-2.5 bg-gray-100/90 backdrop-blur-md rounded-full shadow-md hover:shadow-lg hover:bg-gray-50 transition-all duration-200 border border-gray-300"
            title="Open Menu"
          >
            <Menu className="w-5 h-5 text-gray-800" />
          </button>
        )}

        <div className="h-full w-full flex flex-col">
          {isEmptyChat ? (
            /* Welcome Screen */
            <div className="flex-1 flex flex-col items-center justify-center px-6 pb-20">
              <div className="text-center mb-12 animate-fade-in">
                <h1 className="text-5xl font-bold text-gray-800 mb-3">
                  Hello {userName},
                </h1>
                <p className="text-2xl text-gray-600">
                  Ready to check this out?
                </p>
              </div>
              <InputBar
                input={input}
                isProcessing={isProcessing}
                userId={userId}
                onChange={setInput}
                onSend={() => handleSendMessage(input)}
                onKeyPress={handleKeyPress}
              />
            </div>
          ) : (
            /* Active Chat View */
            <>
              <MessageList
                displayHistory={conversationMessages}
                userId={userId}
                addActiveNode={addActiveNode}
                handleToolResponse={handleToolResponse}
              />
              <div className="p-6 border-t border-white/30 bg-white/10 backdrop-blur-lg">
                <div className="max-w-4xl mx-auto">
                  <InputBar
                    input={input}
                    isProcessing={isProcessing}
                    userId={userId}
                    compact
                    onChange={setInput}
                    onSend={() => handleSendMessage(input)}
                    onKeyPress={handleKeyPress}
                  />
                </div>
              </div>
            </>
          )}
        </div>
      </div>

      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div
          className="fixed inset-0 bg-black/50 z-40 lg:hidden"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}
    </div>
  );
}

import { Send } from "lucide-react";



interface InputBarProps {
    input: string;
    isProcessing: boolean;
    userId: string;
    compact?: boolean;
    onChange: (value: string) => void;
    onSend: () => void;
    onKeyPress: (e: React.KeyboardEvent) => void;
  }

export  function InputBar({ input, isProcessing, userId, compact = false, onChange, onSend, onKeyPress }: InputBarProps) {
    return (
      <div className={compact ? '' : 'w-full max-w-3xl'}>
        <div className="flex gap-3 items-end">
          <div className="flex-1 relative">
            <textarea
              value={input}
              onChange={(e) => onChange(e.target.value)}
              onKeyPress={onKeyPress}
              placeholder={compact ? 'Ask away...' : 'Ask about your marketing data...'}
              disabled={isProcessing || !userId}
              rows={1}
              className={`w-full resize-none text-gray-800 transition-all duration-200 leading-relaxed
                focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent
                disabled:cursor-not-allowed placeholder-gray-400
                ${compact
                  ? 'py-3 pr-4 pl-[52px] border border-white/30 bg-white/20 backdrop-blur-sm rounded-2xl disabled:bg-gray-100/50 disabled:text-gray-500 placeholder-gray-500'
                  : 'py-4 pr-6 pl-[60px] border border-gray-300 bg-white rounded-3xl disabled:bg-gray-100 disabled:text-gray-500 shadow-lg hover:shadow-xl'
                }`}
              style={{
                minHeight: compact ? '50px' : '60px',
                maxHeight: compact ? '150px' : '200px',
                height: 'auto',
              }}
              onInput={(e) => {
                const target = e.target as HTMLTextAreaElement;
                target.style.height = 'auto';
                target.style.height = Math.min(target.scrollHeight, compact ? 150 : 200) + 'px';
              }}
            />
          </div>
          <button
            onClick={onSend}
            disabled={!input.trim() || isProcessing || !userId}
            className={`bg-blue-600 text-white flex items-center gap-2 font-medium
              hover:bg-blue-700 disabled:bg-gray-300 disabled:cursor-not-allowed disabled:shadow-none
              transition-all duration-200 shadow-lg hover:shadow-xl
              ${compact ? 'px-6 py-3 rounded-2xl' : 'px-6 py-4 rounded-3xl'}`}
            title="Send Message"
          >
            <Send className="w-5 h-5" />
            <span>Send</span>
          </button>
        </div>
        <p className={`mt-2 text-center ${compact ? 'text-xs text-gray-600' : 'text-sm text-gray-500 mt-3'}`}>
          Press{' '}
          <kbd className={`font-mono ${compact ? 'px-1.5 py-0.5 bg-white/30 rounded border border-white/40' : 'px-2 py-1 bg-gray-100 rounded border border-gray-300 text-xs'}`}>
            Enter
          </kbd>{' '}
          to send,{' '}
          <kbd className={`font-mono ${compact ? 'px-1.5 py-0.5 bg-white/30 rounded border border-white/40' : 'px-2 py-1 bg-gray-100 rounded border border-gray-300 text-xs'}`}>
            Shift + Enter
          </kbd>{' '}
          for new line
        </p>
      </div>
    );
  }

import { memo, useState, useMemo, useCallback } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import rehypeHighlight from 'rehype-highlight';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';
import { Wrench, ChevronDown, Loader2, Database } from 'lucide-react';

import { toolRegistry } from './message-list';


// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

interface MessageBubbleProps {
    message: any;
    userId: string | undefined;
    delegationStatus?: 'pending' | 'complete' | null;
    // Called by input tools when the user acts — continues the cascade
    onToolComplete: (toolCallId: string, result: string) => Promise<void>;
    // Map of toolCallId → saved tool result message (populated if cascade was replayed)
    toolResults: Record<string, any>;
}


// ---------------------------------------------------------------------------
// MessageBubble
//
// Renders a single message. For assistant messages, also renders any tool
// calls using the toolRegistry. Users should not need to modify this file.
// ---------------------------------------------------------------------------

export const MessageBubble = memo(({
    message,
    userId,
    delegationStatus,
    onToolComplete,
    toolResults,
}: MessageBubbleProps) => {
    const isUser = message.role === 'user';

    // Track which fallback collapsible tool calls are open
    const [openToolCalls, setOpenToolCalls] = useState<Record<number, boolean>>({});

    const toggleOpen = useCallback((index: number) => {
        setOpenToolCalls(prev => ({ ...prev, [index]: !prev[index] }));
    }, []);

    return (
        <div className={`py-4 max-w-4xl mx-auto`}>
            {isUser ? (
                <div className="flex justify-end">
                    <div className="bg-gray-100 rounded-2xl px-4 py-3 max-w-full sm:max-w-2xl">
                        <div className="flex items-start gap-3">
                            <div className="flex-shrink-0 w-6 h-6 rounded-full bg-gray-800 text-white flex items-center justify-center text-xs font-medium mt-0.5">
                                U
                            </div>
                            <div className="text-[15px] leading-relaxed text-gray-900 pt-0.5 break-all">
                                <MarkdownContent content={message.content} />
                            </div>
                        </div>
                    </div>
                </div>
            ) : (
                <div className="flex-1 min-w-0">
                    {message.content && (
                        <div className="text-[15px] leading-relaxed text-gray-900 mb-4">
                            <MarkdownContent content={message.content} />
                        </div>
                    )}

                    {message.tool_calls?.map((toolCall: any, idx: number) => {
                        const savedResult = toolResults[toolCall.id] ?? null;
                        const isFinished = !!savedResult;

                        return (
                            <ToolCallRenderer
                                key={toolCall.id ?? idx}
                                toolCall={toolCall}
                                delegationStatus={delegationStatus}
                                // Bind toolCallId into onComplete so tool components
                                // don't need to know about it — they just call onComplete(result)
                                onComplete={(result: string) => onToolComplete(toolCall.id, result)}
                                isFinished={isFinished}
                                savedResult={savedResult?.content ?? null}
                                isOpen={openToolCalls[idx] || false}
                                onToggle={() => toggleOpen(idx)}
                            />
                        );
                    })}
                </div>
            )}
        </div>
    );
}, (prev, next) => {
    if (prev.userId !== next.userId) return false;
    if (prev.delegationStatus !== next.delegationStatus) return false;
    if (prev.message.content !== next.message.content) return false;
    if (prev.message.tool_calls?.length !== next.message.tool_calls?.length) return false;
    // Check argument changes mid-stream
    return prev.message.tool_calls?.every((tc: any, i: number) =>
        tc.function.arguments === next.message.tool_calls[i]?.function.arguments
    ) ?? true;
});

MessageBubble.displayName = 'MessageBubble';


// ---------------------------------------------------------------------------
// ToolCallRenderer
//
// Handles three cases:
//   1. Delegation tool    — shows a status indicator (pending/complete)
//   2. Registered tool    — looks up toolRegistry and renders the component
//   3. Unregistered tool  — collapsible fallback showing raw arguments
//
// To add a new tool UI, add it to toolRegistry in message-list.tsx.
// You should not need to modify this component.
// ---------------------------------------------------------------------------

const ToolCallRenderer = memo(({
    toolCall,
    delegationStatus,
    onComplete,
    isFinished,
    savedResult,
    isOpen,
    onToggle,
}: {
    toolCall: any;
    delegationStatus?: 'pending' | 'complete' | null;
    onComplete: (result: string) => void;
    isFinished: boolean;
    savedResult: string | null;
    isOpen: boolean;
    onToggle: () => void;
}) => {
    const args = useMemo(() => {
        try {
            return JSON.parse(toolCall.function.arguments);
        } catch {
            // Arguments may still be streaming — return null until complete
            return null;
        }
    }, [toolCall.function.arguments]);

    const toolName = toolCall.function.name;


    // ---
    // Case 1: Delegation tool
    // Rendered as a status indicator, not a full UI.
    // The actual sub-cascade is managed by CascadeMonitor in MessageList.
    // ---
    if (toolName.startsWith('delegate_to_')) {
        if (delegationStatus === 'complete') return null;

        return (
            <div className="flex items-center gap-2 text-sm text-gray-600 mb-3 py-2">
                {delegationStatus === 'pending' ? (
                    <>
                        <Loader2 className="w-4 h-4 text-blue-600 animate-spin" />
                        <span>Retrieving...</span>
                    </>
                ) : (
                    <>
                        <Database className="w-4 h-4 text-gray-500" />
                        <span>Data request</span>
                    </>
                )}
            </div>
        );
    }


    // ---
    // Case 2: Registered tool
    // Look up the tool component from the registry and render it.
    // MessageList has already computed onComplete, isFinished, and savedResult —
    // the tool component just uses them without knowing where they came from.
    // ---
    const RegisteredTool = toolRegistry[toolName];
    if (RegisteredTool) {
        // Don't render until arguments have finished streaming
        if (!args) {
            return (
                <div className="flex items-center gap-2 text-sm text-gray-500 py-2">
                    <Loader2 className="w-3.5 h-3.5 animate-spin" />
                    <span>Loading...</span>
                </div>
            );
        }

        return (
            <div className="my-4">
                <RegisteredTool
                    args={args}
                    onComplete={onComplete}
                    isFinished={isFinished}
                    savedResult={savedResult}
                />
            </div>
        );
    }


    // ---
    // Case 3: Unregistered tool — collapsible fallback
    // Shows the raw tool name and arguments so you can see what the LLM called.
    // Add the tool to toolRegistry in message-list.tsx to give it a proper UI.
    // ---
    return (
        <div className="my-3 border border-gray-200 rounded-lg overflow-hidden bg-gray-50">
            <button
                onClick={onToggle}
                className="w-full flex items-center gap-2 p-2.5 text-left hover:bg-gray-100 transition-colors"
            >
                <Wrench className="w-3.5 h-3.5 text-gray-500" />
                <span className="text-xs font-medium text-gray-600 flex-1">{toolName}</span>
                <ChevronDown className={`w-3.5 h-3.5 text-gray-400 transition-transform ${isOpen ? 'rotate-180' : ''}`} />
            </button>
            {isOpen && (
                <div className="px-2.5 pb-2.5 pt-0 border-t border-gray-200 bg-white">
                    <pre className="text-[10px] text-gray-700 font-mono bg-gray-50 p-2 rounded mt-2 overflow-x-auto whitespace-pre-wrap">
                        {args ? JSON.stringify(args, null, 2) : toolCall.function.arguments}
                    </pre>
                </div>
            )}
        </div>
    );
});

ToolCallRenderer.displayName = 'ToolCallRenderer';


// ---------------------------------------------------------------------------
// MarkdownContent
// ---------------------------------------------------------------------------

export const MarkdownContent = memo(({ content }: { content: string }) => (
    <div className="markdown-content text-gray-900">
        <ReactMarkdown
            remarkPlugins={[remarkGfm, remarkMath]}
            rehypePlugins={[rehypeHighlight, rehypeKatex]}
            components={{
                h1: ({ children }) => <h1 className="text-2xl font-bold mt-5 mb-3 border-b border-gray-300 pb-2">{children}</h1>,
                h2: ({ children }) => <h2 className="text-xl font-semibold mt-4 mb-2">{children}</h2>,
                h3: ({ children }) => <h3 className="text-lg font-semibold mt-3 mb-2">{children}</h3>,
                p: ({ children }) => <p className="mb-3 leading-relaxed">{children}</p>,
                ul: ({ children }) => <ul className="list-disc list-inside space-y-1.5 ml-4 my-3">{children}</ul>,
                ol: ({ children }) => <ol className="list-decimal list-inside space-y-1.5 ml-4 my-3">{children}</ol>,
                li: ({ children }) => <li className="pl-1">{children}</li>,
                a: ({ children, href }) => (
                    <a href={href} className="text-blue-600 hover:underline" target="_blank" rel="noopener noreferrer">
                        {children}
                    </a>
                ),
                img: ({ src, alt }) => (
                    <span className="block my-4">
                        <img
                            src={src}
                            alt={alt || 'image'}
                            className="max-w-full h-auto rounded-lg border border-gray-200 shadow-sm"
                            loading="lazy"
                        />
                        {alt && <span className="text-xs text-gray-500 mt-1 block text-center">{alt}</span>}
                    </span>
                ),
                code: ({ className, children }: any) => {
                    if (!className) {
                        return <code className="bg-gray-200 text-gray-800 px-1.5 py-0.5 rounded text-sm font-mono">{children}</code>;
                    }
                    return children;
                },
                table: ({ children }) => (
                    <div className="overflow-x-auto my-4 border border-gray-300 rounded-lg shadow-sm">
                        <table className="min-w-full divide-y divide-gray-300">{children}</table>
                    </div>
                ),
                th: ({ children }) => <th className="px-6 py-3 bg-gray-50 text-left text-xs font-medium text-gray-600 uppercase tracking-wider">{children}</th>,
                td: ({ children }) => <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-800 border-t border-gray-200">{children}</td>,
            }}
        >
            {content}
        </ReactMarkdown>
    </div>
));

MarkdownContent.displayName = 'MarkdownContent';

import { v4 as uuidv4 } from 'uuid';
import React, { useState, useEffect, useMemo, useCallback, memo } from 'react';
import { Bot, Loader2, Database } from 'lucide-react';
import { useCascade } from '@cascaide-ts/react';
import { MessageBubble } from './message-bubble';

// ---------------------------------------------------------------------------
// TOOL REGISTRY
//
// This is the main place you extend the chat UI.
//
// Each key is a tool name your LLM can call.
// Each value is a React component that receives:
//   - args        — parsed tool call arguments (what the LLM passed)
//   - onComplete  — call this with a string result to send a tool response
//                   and continue the cascade. Omit if this is display-only.
//   - isFinished  — true if a tool response already exists (e.g. on reload)
//   - savedResult — the existing tool response string if isFinished is true
//
// DISPLAY TOOL (no user interaction):
//   my_chart_tool: ({ args }) => <ChartRenderer data={args.data} />
//
// INPUT TOOL (user acts, cascade continues):
//   my_approval_tool: ({ args, onComplete, isFinished, savedResult }) => (
//     <ApprovalCard
//       request={args.request}
//       onApprove={() => onComplete('approved')}
//       onReject={() => onComplete('rejected')}
//       isFinished={isFinished}
//       savedResult={savedResult}
//     />
//   )
// ---------------------------------------------------------------------------

import { HotelOptions } from './tool-ui/hotel-tool';

export type ToolComponentProps = {
    args: any;
    onComplete: (result: string) => void;
    isFinished: boolean;
    savedResult: string | null;
};

export const toolRegistry: Record<string, React.ComponentType<ToolComponentProps>> = {
    // ---
    // Example input tool: user selects a hotel, cascade continues with their choice.
    // Replace or extend this with your own tools.
    // ---
    present_hotel_options: HotelOptions,
};


// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

type DelegationStatus = 'pending' | 'complete';

type Delegation = {
    subCascadeId: string;
    toolCallId: string;
    agentName: string;
    status: DelegationStatus;
};


// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

// Converts 'delegate_to_availabilityAgentNode' → 'availabilityAgentNode'
// Matches the node name convention in your graph.
// Update this if your delegation tool naming convention differs.
const getSubAgentNodeName = (toolName: string): string | null => {
    if (toolName.startsWith('delegate_to_')) {
        return toolName.replace('delegate_to_', '') + 'Node';
    }
    return null;
};



// ---------------------------------------------------------------------------
// MessageList
//
// Owns two things:
//   1. Delegation orchestration — spawning sub-cascades when the supervisor
//      delegates to a sub-agent, and returning results via handleToolResponse.
//   2. Tool rendering — looking up tool components from the registry and
//      wiring their onComplete → handleToolResponse automatically.
//
// Users should not need to modify this file to add new tools.
// Add tool UIs to toolRegistry above instead.
// ---------------------------------------------------------------------------

export const MessageList = memo(({
    displayHistory,
    userId,
    addActiveNode,
    handleToolResponse,
}: {
    displayHistory: any[];
    userId: string | undefined;
    // addActiveNode comes from useWorkflow — triggers a node execution in the graph
    addActiveNode: any;
    // handleToolResponse sends a tool result message and continues the cascade
    handleToolResponse: any;
}) => {
    // Tracks all delegations: their cascade ID, agent name, and completion status.
    // A single map is used so parallel delegations can be managed together.
    const [delegations, setDelegations] = useState<Map<string, Delegation>>(new Map());

    const getDelegationStatus = (toolCallId: string): DelegationStatus | null =>
        delegations.get(toolCallId)?.status ?? null;


    // ---
    // Delegation detection
    //
    // When the supervisor calls a 'delegate_to_*' tool, we:
    //   1. Spawn a new sub-cascade for the sub-agent via addActiveNode (useWorkflow)
    //   2. Track it in state so CascadeMonitor can observe it via useCascade
    //   3. When the sub-cascade completes, send its result back as a tool response
    //
    // This runs whenever displayHistory changes, checking only the last assistant message
    // to avoid reprocessing previous delegations.
    // ---
    useEffect(() => {
        const processDelegations = async () => {
            if (displayHistory.length === 0) return;

            const lastAssistantIndex = displayHistory.findLastIndex(
                msg => msg.role === 'assistant' && msg.tool_calls
            );
            if (lastAssistantIndex === -1) return;

            const lastAssistantMessage = displayHistory[lastAssistantIndex];
            const delegationTools = lastAssistantMessage.tool_calls.filter((tc: any) =>
                tc.function.name.startsWith('delegate_to_')
            );
            if (delegationTools.length === 0) return;

            for (const toolCall of delegationTools) {
                // Skip if already being tracked
                if (delegations.has(toolCall.id)) continue;

                // If a tool result already exists in history, mark complete immediately
                const hasToolResult = displayHistory.slice(lastAssistantIndex + 1).some(msg =>
                    msg.role === 'tool' && msg.tool_call_id === toolCall.id
                );
                if (hasToolResult) {
                    setDelegations(prev => {
                        const next = new Map(prev);
                        next.set(toolCall.id, {
                            subCascadeId: '',
                            toolCallId: toolCall.id,
                            agentName: '',
                            status: 'complete',
                        });
                        return next;
                    });
                    continue;
                }

                // Wait for arguments to finish streaming before parsing
                const argsString = toolCall.function.arguments;
                if (!argsString?.trim().endsWith('}')) {
                    if (lastAssistantIndex === displayHistory.length - 1) continue;
                }

                try {
                    const args = JSON.parse(argsString);
                    const subNodeName = getSubAgentNodeName(toolCall.function.name);
                    const query = args.query;
                    if (!subNodeName || !query) {
                        console.error('Invalid delegation arguments:', toolCall);
                        continue;
                    }

                    const newSubCascadeId = `sub_cascade_${uuidv4()}`;

                    setDelegations(prev => {
                        const next = new Map(prev);
                        next.set(toolCall.id, {
                            subCascadeId: newSubCascadeId,
                            toolCallId: toolCall.id,
                            agentName: subNodeName,
                            status: 'pending',
                        });
                        return next;
                    });

                    // Trigger the sub-agent node in the graph.
                    // The sub-cascade ID links this execution to CascadeMonitor below.
                    await addActiveNode(subNodeName, {
                        cascadeId: newSubCascadeId,
                        history: [{ role: 'user', content: query.trim() }],
                        originalToolCallId: toolCall.id,
                        userId,
                    });
                } catch (error) {
                    console.error('Error processing delegation:', error);
                }
            }
        };

        processDelegations();
    }, [displayHistory.length, displayHistory[displayHistory.length - 1]]);


    // ---
    // Called by CascadeMonitor when a sub-cascade completes.
    // Sends the result back as a tool response to continue the parent cascade,
    // then marks the delegation complete.
    // ---
    const handleDelegationComplete = useCallback((toolCallId: string, result: string) => {
        handleToolResponse({
            role: 'tool',
            tool_call_id: toolCallId,
            content: result || 'Sub-cascade completed successfully.',
        });

        setDelegations(prev => {
            const next = new Map(prev);
            const existing = next.get(toolCallId);
            if (existing) next.set(toolCallId, { ...existing, status: 'complete' });
            return next;
        });
    }, [handleToolResponse]);


    // Clean up completed delegations once all parallel ones are done
    useEffect(() => {
        const values = Array.from(delegations.values());
        if (values.some(d => d.status === 'pending')) return;
        if (!values.some(d => d.status === 'complete')) return;

        setDelegations(prev => {
            const next = new Map(prev);
            for (const [id, d] of next) {
                if (d.status === 'complete') next.delete(id);
            }
            return next;
        });
    }, [delegations]);


    const showAILoading = useMemo(() =>
        displayHistory.length > 0 &&
        displayHistory[displayHistory.length - 1]?.role === 'user' &&
        delegations.size === 0,
        [displayHistory.length, displayHistory[displayHistory.length - 1]?.role, delegations.size]
    );

    const activeDelegations = useMemo(() =>
        Array.from(delegations.values()).filter(d => d.status === 'pending'),
        [delegations]
    );

    return (
        <div className="flex-1 overflow-y-auto px-6 py-4">
            <div className="max-w-4xl mx-auto">
                {displayHistory.map((msg, idx) => {
                    // Skip raw tool result messages — they are consumed by the tool UI
                    if (msg.role === 'tool') return null;

                    // For each registered tool call in this message, find if a tool
                    // response already exists in history (used for isFinished + savedResult)
                    const toolResults: Record<string, any> = {};
                    msg.tool_calls?.forEach((tc: any) => {
                        const result = displayHistory.slice(idx + 1).find(
                            m => m.role === 'tool' && m.tool_call_id === tc.id
                        );
                        if (result) toolResults[tc.id] = result;
                    });

                    // Find delegation tool call for status indicator in MessageBubble
                    const delegationTool = msg.tool_calls?.find((tc: any) =>
                        tc.function.name.startsWith('delegate_to_')
                    );

                    return (
                        <div key={`${idx}-${msg.role}`}>
                            <MessageBubble
                                message={msg}
                                userId={userId}
                                delegationStatus={delegationTool
                                    ? getDelegationStatus(delegationTool.id)
                                    : null
                                }
                                // Wire tool registry: MessageBubble receives handleToolResponse
                                // and toolResults so it can build onComplete and isFinished
                                // for each tool component without exposing those internals
                                // to the tool components themselves.
                                onToolComplete={async (toolCallId, result) => {
                                    await handleToolResponse({
                                        role: 'tool',
                                        tool_call_id: toolCallId,
                                        content: result,
                                    });
                                }}
                                toolResults={toolResults}
                            />
                        </div>
                    );
                })}

                {/* Shown while the LLM is generating a response */}
                {showAILoading && (
                    <div className="flex items-start gap-4 py-4">
                        <div className="flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center bg-gradient-to-br from-blue-500 to-indigo-600 text-white">
                            <Bot className="w-4 h-4" />
                        </div>
                        <div className="flex-1 min-w-0">
                            <div className="text-sm font-semibold mb-2 text-gray-500">Assistant</div>
                            <div className="rounded-xl px-4 py-3 bg-transparent border border-blue-100">
                                <div className="flex items-center gap-2">
                                    <Loader2 className="w-4 h-4 text-blue-600 animate-spin" />
                                    <span className="text-base text-gray-600">Thinking...</span>
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {/* One CascadeMonitor per active sub-cascade.
                    Each one uses useCascade to observe its sub-cascade and calls
                    handleDelegationComplete when done. */}
                {activeDelegations.map(delegation => (
                    <CascadeMonitor
                        key={delegation.subCascadeId}
                        subCascadeId={delegation.subCascadeId}
                        toolCallId={delegation.toolCallId}
                        agentName={delegation.agentName}
                        onComplete={handleDelegationComplete}
                    />
                ))}
            </div>
        </div>
    );
});

